function makeLessonJs(slug) {
  const lesson = (window.A1_SECTIONS || {})[slug] || [];
  return 'window.A1_SECTIONS = window.A1_SECTIONS || {};\n' +
    'window.A1_SECTIONS[' + JSON.stringify(slug) + '] = ' + JSON.stringify(lesson, null, 2) + ';\n';
}

function downloadText(filename, text) {
  const mime = filename.endsWith('.html') ? 'text/html;charset=utf-8' : 'text/javascript;charset=utf-8';
  const blob = new Blob([text], {type:mime});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function downloadBlob(filename, blob) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function downloadEditedLessonFile() {
  const updated = buildEditedItem();
  if (!updated) return;
  replaceFullItem(updated);
  const meta = state.items.find(x => x.id === updated.id);
  if (!meta) return;
  const filename = (meta.lesson_file || `${meta.lesson_slug}.js`).split('/').pop();
  downloadText(filename, makeLessonJs(meta.lesson_slug));
  renderList();
  showPreview(updated.id, false);
}

function typesetPreview() {
  if (window.MathJax && MathJax.typesetPromise) MathJax.typesetPromise([$('preview')]);
}


const WORKSPACE_DATA_URIS = {"coordinate":"data:image/png;base64,","quadrant":"data:image/png;base64,","square":"data:image/png;base64,","dot":"data:image/png;base64,","numberline":"data:image/png;base64,","numberline_neg10":"data:image/png;base64,","unit_circle":"data:image/png;base64,"};

// ── NEW QUESTION ─────────────────────────────────────────────────
function lessonOptionsForNewQuestion() {
  const fromCatalog = state.items.map(meta => ({slug: meta.lesson_slug, label: `${meta.section} — ${meta.lesson_file || meta.lesson_slug + '.js'}`}));
  const fromLessons = Object.keys(window.A1_SECTIONS || {}).map(slug => {
    const lesson = (window.A1_SECTIONS || {})[slug] || [];
    const first = lesson[0] || {};
    return {slug, label: `${first.section || slug.replace(/_/g,'.')} — ${slug}.js`};
  });
  const map = new Map();
  [...fromCatalog, ...fromLessons].forEach(x => { if (x.slug && !map.has(x.slug)) map.set(x.slug, x.label); });
  return [...map.entries()].map(([slug,label]) => ({slug,label})).sort((a,b)=>a.label.localeCompare(b.label, undefined, {numeric:true}));
}

function populateNewLessonChoices() {
  const select = $('newLessonSlug');
  const opts = lessonOptionsForNewQuestion();
  select.innerHTML = opts.map(opt => `<option value="${escapeHtml(opt.slug)}">${escapeHtml(opt.label)}</option>`).join('');
}

function populateNewSourceTypes(current='Teacher Created') {
  $('newSourceType').innerHTML = sourceTypes().map(src => `<option value="${escapeHtml(src)}" ${src===current?'selected':''}>${escapeHtml(src)}</option>`).join('');
}

function nextTeacherQuestionIdentity(slug) {
  const lesson = (window.A1_SECTIONS || {})[slug] || [];
  const sample = lesson[0] || {};
  const section = $('newSection') && $('newSection').value.trim() ? $('newSection').value.trim() : (sample.section || slug.replace(/^lesson_/, '').replace(/_/g,'.'));
  const base = section.replace(/[^0-9A-Za-z]+/g, '-').replace(/^-+|-+$/g, '') || slug.replace(/[^0-9A-Za-z]+/g, '-');
  let max = 0;
  lesson.forEach(item => {
    const id = String(item.id || '');
    const m = id.match(new RegExp(`^a1-tc-${base}-(\\d+)$`));
    if (m) max = Math.max(max, parseInt(m[1], 10));
  });
  const n = String(max + 1).padStart(3, '0');
  return {id: `a1-tc-${base}-${n}`, number: `TC ${section}-${n}`};
}

function updateNewLessonDefaults(forceIdentity=false) {
  const slug = $('newLessonSlug').value;
  const lesson = (window.A1_SECTIONS || {})[slug] || [];
  const sample = lesson[0] || {};
  if (forceIdentity || !$('newChapter').value) $('newChapter').value = sample.chapter || 'Unit 1: Foundations of Functions and Algebra';
  if (forceIdentity || !$('newSection').value) $('newSection').value = sample.section || slug.replace(/^lesson_/, '').replace(/_/g,'.');
  const ident = nextTeacherQuestionIdentity(slug);
  $('newId').value = ident.id;
  $('newNumber').value = ident.number;
  updateNewViewPreview();
}

