function assetSrcsFromHtml(html) {
  const d = document.createElement('div');
  d.innerHTML = html || '';
  return [...d.querySelectorAll('img[src]')]
    .map(img => img.getAttribute('src'))
    .filter(src => src && !src.startsWith('data:') && !/^https?:\/\//i.test(src));
}
function normalizeAssetPath(src) {
  let clean = String(src || '').replace(/^\.\//, '');
  clean = clean.replace(/^\.\.\//, '');
  if (clean.startsWith('/')) clean = clean.slice(1);
  const idx = clean.indexOf('assets/');
  if (idx >= 0) clean = clean.slice(idx);
  return clean;
}
function rewriteAssetPathsInHtml(html) {
  const d = document.createElement('div');
  d.innerHTML = html || '';
  d.querySelectorAll('img[src]').forEach(img => {
    const src = img.getAttribute('src');
    if (src && !src.startsWith('data:') && !/^https?:\/\//i.test(src)) img.setAttribute('src', normalizeAssetPath(src));
  });
  return d.innerHTML;
}
function sanitizeBankItemForExport(item) {
  const out = JSON.parse(JSON.stringify(item));
  out.html = rewriteAssetPathsInHtml(out.html || '');
  out.text_preview = out.text_preview || textFromHtml(out.html);
  return out;
}
function exportBankPreviewHtml(title, items) {
  const cards = items.map((item, idx) => {
    const standards = Array.isArray(item.standards) && item.standards.length ? item.standards.join(', ') : '';
    const tags = Array.isArray(item.tags) && item.tags.length ? item.tags.join(', ') : '';
    const resources = Array.isArray(item.resources) && item.resources.length
      ? `<div class="bank-resources"><strong>Resources:</strong> ${item.resources.map(r => `<a href="${escapeHtml(r.url || r.href || '#')}" target="_blank" rel="noopener">${escapeHtml(r.label || r.url || r.href || 'resource')}</a>`).join(' · ')}</div>`
      : '';
    return `<article class="bank-card">
      <header><div class="bank-num">${idx+1}. ${escapeHtml(item.number)}</div><div class="bank-sub">${escapeHtml(item.section)} · ${escapeHtml(item.source_type)} · ${escapeHtml(item.id)}</div></header>
      <div class="bank-meta"><span><b>Original Source:</b> ${escapeHtml(item.original_source || '')}</span><span><b>Source Lesson:</b> ${escapeHtml(item.source_lesson || '')}</span><span><b>Audit Status:</b> ${escapeHtml(item.audit_status || '')}</span><span><b>Source File:</b> ${escapeHtml(item.source_file || item.lesson_file || '')}</span><span><b>Topic:</b> ${escapeHtml(item.topic || '')}</span><span><b>Standards:</b> ${escapeHtml(standards)}</span><span><b>Tags:</b> ${escapeHtml(tags)}</span><span><b>DOK:</b> ${escapeHtml(item.dok || '')}</span><span><b>Notes:</b> ${escapeHtml(item.notes || item.teacher_notes || '')}</span></div>
      ${item.html}
      ${resources}
    </article>`;
  }).join('\n');
  const css = `body{margin:0;background:#f3f6fb;color:#111827;font-family:Arial,sans-serif}.bank-wrap{max-width:1000px;margin:0 auto;padding:24px}.bank-title{background:#0d3060;color:#fff;border-radius:14px;padding:18px 22px;margin-bottom:18px}.bank-title h1{margin:0 0 6px;font-size:28px}.bank-title p{margin:0;color:#bfdbfe}.bank-card{background:#fff;border:1px solid #dbe3ef;border-radius:14px;margin:0 0 18px;padding:18px 20px;box-shadow:0 1px 5px rgba(0,0,0,.06)}.bank-card header{display:flex;justify-content:space-between;gap:16px;border-bottom:1px solid #e5e7eb;padding-bottom:8px;margin-bottom:12px}.bank-num{font-weight:800;font-size:18px;color:#0d3060}.bank-sub{font-family:monospace;color:#64748b}.bank-meta{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:6px 14px;background:#f8fafc;border:1px solid #e5e7eb;border-radius:10px;padding:10px 12px;margin-bottom:12px;font-size:13px}.bank-card .catalog-card-content,.bank-card .problem{font-family:Georgia,'Times New Roman',serif;font-size:16px;line-height:1.45}.bank-card img{max-width:100%;height:auto;display:block;margin:10px auto}.resources,.bank-resources{margin-top:10px;font-size:13px}.bank-resources a{color:#0d63c7}@media print{body{background:#fff}.bank-wrap{padding:0}.bank-title{border-radius:0}.bank-card{break-inside:avoid;box-shadow:none}}`;
  return `<!doctype html><html lang="en"><head><meta charset="utf-8"><title>${escapeHtml(title)}</title><style>${css}</style><script>MathJax={tex:{inlineMath:[['$','$']],displayMath:[['$$','$$']]}};<\/script><script async src="https://cdn.jsdelivr.net/npm/mathjax@3/es5/tex-mml-chtml.js"><\/script></head><body><div class="bank-wrap"><section class="bank-title"><h1>${escapeHtml(title)}</h1><p>${items.length} exported problems. Includes source metadata, teacher fields, resources, and cleaned HTML.</p></section>${cards}</div></body></html>`;
}
function makeExportReadme(title, mode, count, missing) {
  return `# ${title}\n\nExport mode: ${mode}\nProblem count: ${count}\n\nFiles included:\n- bank_preview.html: human-readable preview with metadata and images\n- bank_data.json: raw exported item data for AI/upload workflows\n- bank_data.js: same data as a JS variable for app experiments\n- assets/: copied images referenced by the exported problems, when the browser could access them\n\nUse case examples:\n- Upload this ZIP to ChatGPT and ask for a formative assessment using the bank as source material.\n- Upload bank_data.json and ask for teacher-created variants.\n- Use the item IDs and lesson_slug fields to merge new teacher-created items back into lesson JS files.\n\n${missing.length ? 'Missing or inaccessible assets:\n' + missing.map(x => '- ' + x).join('\n') + '\n\nIf assets are missing, run the catalog from a local server or GitHub Pages and export again.' : 'All detected local image assets were bundled successfully.'}\n`;
}
async function addBankAssetsToZip(zip, items) {
  const paths = [...new Set(items.flatMap(item => assetSrcsFromHtml(item.html).map(normalizeAssetPath)))];
  const missing = [];
  for (const path of paths) {
    try {
      const response = await fetch(encodeURI(path));
      if (!response.ok) throw new Error('HTTP ' + response.status);
      const blob = await response.blob();
      zip.file(path, blob);
    } catch (err) {
      missing.push(path);
    }
  }
  return missing;
}
async function exportBankZip(mode) {
  if (!window.JSZip) {
    alert('JSZip did not load. Check your internet connection, then reload this page.');
    return;
  }
  const raw = exportTargetItems(mode);
  if (!raw.length) {
    alert(mode === 'selected' ? 'No problems are selected.' : 'No filtered problems to export.');
    return;
  }
  const items = raw.map(sanitizeBankItemForExport);
  const zip = new JSZip();
  const title = mode === 'selected' ? 'Algebra 1 Selected Problem Bank Export' : 'Algebra 1 Filtered Problem Bank Export';
  setPreviewStatus(`Building ${items.length}-problem bank export...`);
  const missing = await addBankAssetsToZip(zip, items);
  zip.file('bank.html', exportBankPreviewHtml(title, items));
  const blob = await zip.generateAsync({type:'blob'});
  const date = new Date().toISOString().slice(0,10);
  const safeMode = mode === 'selected' ? 'selected' : 'filtered';
  downloadBlob(`cc1_${safeMode}_bank_${date}.zip`, blob);
  setPreviewStatus(`${items.length}-problem ${safeMode} bank ZIP downloaded with bank.html${missing.length ? ` (${missing.length} asset(s) not bundled)` : ''}`);
}

document.addEventListener('DOMContentLoaded', init);
